```cpp
// 區間排程貪心（最大不相交區間數）
// 按右端點排序，依次選擇不衝突的區間
sort(intervals.begin(), intervals.end(), [](auto& a, auto& b) { return a[1] < b[1]; });
int cnt = 0, last = INT_MIN;
for (auto& it : intervals) {
    if (it[0] >= last) {
        cnt++;
        last = it[1];
    }
}
